/**
 * @summary Get distinct values for a CRM contact field (for filter dropdowns)
 */
export const getListCrmContactDistinctValuesUrl = (
  params: ListCrmContactDistinctValuesParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/crm/contacts/distinct-values?${stringifiedParams}`
    : `/api/crm/contacts/distinct-values`;
};

